		@Query() query: FrequentlyBoughtTogetherRootCategoriesQueryDto,
	): Promise<FrequentlyBoughtTogetherRootCategoriesResponseDto> {
		return this.frequentlyBoughtTogetherService.getFrequentlyBoughtTogetherByRootCategories(
			query,
		);
	}

	@Get('v2')
